// HubSpot deal webhooks arrive as an array of change events (or a single object).
const body = items[0].json;
const ev = Array.isArray(body) ? body[0] : (body.payload || body.event || body);
const dealId = String(ev.objectId || ev.dealId || ev.id || '');
const stage = String(ev.propertyValue || ev.dealstage || ev.stage || '');
const dryRun = String($env.PP_DRY_RUN || '').toLowerCase() === 'true' || body.dryRun === true;
if (!dealId) { throw new Error('Pipeline Truth Sync: no deal id in webhook payload'); }
return [{ json: { dealId, stage, dryRun, receivedAt: new Date().toISOString() } }];

// Idempotency: dedupe on the HubSpot deal id (+ stage) using n8n static data.
// NOTE: static data persists only across PRODUCTION (active) executions. For
// cross-instance dedupe, back this with Redis/KV (see README).
const data = $getWorkflowStaticData('global');
data.synced = data.synced || {};
const j = items[0].json;
const dedupeKey = j.dealId + ':' + j.stage;
const duplicate = Boolean(data.synced[dedupeKey]);
return [{ json: { ...j, dedupeKey, duplicate } }];

const j = items[0].json;
console.log('[pipeline-truth-sync] duplicate deal, skipping', j.dedupeKey);
return [{ json: { ...j, result: 'skipped-duplicate' } }];

// Pull the deal + associated contact + stored click ids into one conversion.
const base = $('Check Idempotency').first().json;
const deal = $('Read Deal').first().json || {};
let contact = {};
try { contact = $('Read Contact').first().json || {}; } catch (e) { contact = {}; }
const dp = deal.properties || {};
const cp = contact.properties || {};
const pick = (k) => dp['pp_' + k] || cp['pp_' + k] || null; // prefer deal, fall back to contact
const amount = Number(dp.amount || 0);
const stage = String(dp.dealstage || base.stage || '');
const isClosedWon = /closedwon/i.test(stage);
const closeMs = dp.closedate ? Date.parse(dp.closedate) : Date.now();
return [{ json: {
  dealId: base.dealId,
  dedupeKey: base.dedupeKey,
  dryRun: base.dryRun,
  stage,
  isClosedWon,
  value: amount,
  currency: $env.PP_CONVERSION_CURRENCY || 'USD',
  gclid: pick('gclid'),
  fbclid: pick('fbclid'),
  ttclid: pick('ttclid'),
  email: cp.email || null,
  eventTimeUnix: Math.floor(closeMs / 1000),
  eventTimeIso: new Date(closeMs).toISOString(),
} }];

const c = items[0].json;
const RES = { platform: 'meta', status: 'skipped', httpStatus: null, detail: '' };
if (!c.fbclid) { RES.detail = 'no fbclid'; return [{ json: { ...c, meta: RES } }]; }
if (c.dryRun) { RES.status = 'dry-run'; RES.detail = 'PP_DRY_RUN'; return [{ json: { ...c, meta: RES } }]; }
const token = $env.META_CAPI_TOKEN, pixel = $env.META_PIXEL_ID;
if (!token || !pixel) { RES.status = 'error'; RES.detail = 'META_CAPI_TOKEN / META_PIXEL_ID unset'; return [{ json: { ...c, meta: RES } }]; }
const url = 'https://graph.facebook.com/v21.0/' + pixel + '/events?access_token=' + token;
const body = { data: [{ event_name: 'Purchase', event_time: c.eventTimeUnix, action_source: 'crm', event_id: 'pp_' + c.dealId, user_data: { fbc: c.fbclid }, custom_data: { value: c.value, currency: c.currency } }] };
let a = 0; const max = 5;
while (a < max) {
  try {
    const r = await this.helpers.httpRequest({ method: 'POST', url, body, json: true, returnFullResponse: true });
    RES.status = 'sent'; RES.httpStatus = r.statusCode; RES.detail = 'ok'; break;
  } catch (e) {
    RES.httpStatus = e.httpCode || e.statusCode || null;
    if (a === max - 1) { RES.status = 'error'; RES.detail = String(e.message || e).slice(0, 200); }
    else { await new Promise(x => setTimeout(x, Math.min(30000, 500 * 2 ** a) + Math.floor(Math.random() * 250))); }
    a++;
  }
}
return [{ json: { ...c, meta: RES } }];

const c = items[0].json;
const RES = { platform: 'google', status: 'skipped', httpStatus: null, detail: '' };
if (!c.gclid) { RES.detail = 'no gclid'; return [{ json: { ...c, google: RES } }]; }
if (c.dryRun) { RES.status = 'dry-run'; RES.detail = 'PP_DRY_RUN'; return [{ json: { ...c, google: RES } }]; }
const cust = $env.GOOGLE_ADS_CUSTOMER_ID, dev = $env.GOOGLE_ADS_DEVELOPER_TOKEN, tok = $env.GOOGLE_ADS_ACCESS_TOKEN, action = $env.GOOGLE_ADS_CONVERSION_ACTION;
if (!cust || !dev || !tok || !action) { RES.status = 'error'; RES.detail = 'GOOGLE_ADS_* env unset'; return [{ json: { ...c, google: RES } }]; }
const d = new Date(c.eventTimeUnix * 1000), pad = (n) => String(n).padStart(2, '0');
const cdt = d.getUTCFullYear() + '-' + pad(d.getUTCMonth() + 1) + '-' + pad(d.getUTCDate()) + ' ' + pad(d.getUTCHours()) + ':' + pad(d.getUTCMinutes()) + ':' + pad(d.getUTCSeconds()) + '+00:00';
const url = 'https://googleads.googleapis.com/v17/customers/' + cust + ':uploadClickConversions';
const headers = { 'developer-token': dev, 'login-customer-id': cust, Authorization: 'Bearer ' + tok };
const body = { partialFailure: true, conversions: [{ gclid: c.gclid, conversionAction: action, conversionDateTime: cdt, conversionValue: c.value, currencyCode: c.currency }] };
let a = 0; const max = 5;
while (a < max) {
  try {
    const r = await this.helpers.httpRequest({ method: 'POST', url, headers, body, json: true, returnFullResponse: true });
    RES.status = 'sent'; RES.httpStatus = r.statusCode; RES.detail = 'ok'; break;
  } catch (e) {
    RES.httpStatus = e.httpCode || e.statusCode || null;
    if (a === max - 1) { RES.status = 'error'; RES.detail = String(e.message || e).slice(0, 200); }
    else { await new Promise(x => setTimeout(x, Math.min(30000, 500 * 2 ** a) + Math.floor(Math.random() * 250))); }
    a++;
  }
}
return [{ json: { ...c, google: RES } }];

const c = items[0].json;
const RES = { platform: 'tiktok', status: 'skipped', httpStatus: null, detail: '' };
if (!c.ttclid) { RES.detail = 'no ttclid'; return [{ json: { ...c, tiktok: RES } }]; }
if (c.dryRun) { RES.status = 'dry-run'; RES.detail = 'PP_DRY_RUN'; return [{ json: { ...c, tiktok: RES } }]; }
const tok = $env.TIKTOK_ACCESS_TOKEN, eventSet = $env.TIKTOK_EVENT_SET_ID;
if (!tok || !eventSet) { RES.status = 'error'; RES.detail = 'TIKTOK_* env unset'; return [{ json: { ...c, tiktok: RES } }]; }
const url = 'https://business-api.tiktok.com/open_api/v1.3/event/track/';
const headers = { 'Access-Token': tok, 'Content-Type': 'application/json' };
const body = { event_source: 'offline', event_source_id: eventSet, data: [{ event: 'CompletePayment', event_time: c.eventTimeUnix, event_id: 'pp_' + c.dealId, user: { ttclid: c.ttclid }, properties: { value: c.value, currency: c.currency, content_type: 'deal' } }] };
let a = 0; const max = 5;
while (a < max) {
  try {
    const r = await this.helpers.httpRequest({ method: 'POST', url, headers, body, json: true, returnFullResponse: true });
    RES.status = 'sent'; RES.httpStatus = r.statusCode; RES.detail = 'ok'; break;
  } catch (e) {
    RES.httpStatus = e.httpCode || e.statusCode || null;
    if (a === max - 1) { RES.status = 'error'; RES.detail = String(e.message || e).slice(0, 200); }
    else { await new Promise(x => setTimeout(x, Math.min(30000, 500 * 2 ** a) + Math.floor(Math.random() * 250))); }
    a++;
  }
}
return [{ json: { ...c, tiktok: RES } }];

const j = items[0].json;
console.log('[pipeline-truth-sync] stage change but not closed-won, no conversion', j.dealId, j.stage);
return [{ json: { ...j, result: 'noop-not-closed-won' } }];

// Three parallel senders converge here (three items on one input).
const all = items.map(i => i.json);
const base = all[0] || {};
const results = {
  meta: (all.find(x => x.meta) || {}).meta || null,
  google: (all.find(x => x.google) || {}).google || null,
  tiktok: (all.find(x => x.tiktok) || {}).tiktok || null,
};
const anySent = Object.values(results).some(r => r && r.status === 'sent');
const anyError = Object.values(results).some(r => r && r.status === 'error');
// Mark synced when we made progress (a real send or a clean dry-run). If every
// platform errored we DON'T mark, so the next event can safely retry.
const data = $getWorkflowStaticData('global');
data.synced = data.synced || {};
const marked = Boolean(base.dedupeKey && (anySent || base.dryRun));
if (marked) { data.synced[base.dedupeKey] = new Date().toISOString(); }
const line = (p, r) => p + ': ' + (r ? (r.status + (r.httpStatus ? ' (' + r.httpStatus + ')' : '') + (r.detail ? ' — ' + r.detail : '')) : 'n/a');
const slackText = [
  '*Pipeline Truth Sync* — deal ' + base.dealId + (base.dryRun ? '  _(DRY-RUN)_' : ''),
  'value: ' + base.value + ' ' + base.currency,
  line('Meta', results.meta),
  line('Google', results.google),
  line('TikTok', results.tiktok),
  anyError ? ':warning: a platform failed — not fully marked, will retry on next event' : ':white_check_mark: marked synced',
].join('\n');
const summary = { dealId: base.dealId, dedupeKey: base.dedupeKey, dryRun: base.dryRun, value: base.value, currency: base.currency, results, anyError, marked, slackText, finishedAt: new Date().toISOString() };
console.log('[pipeline-truth-sync]', JSON.stringify({ ...summary, slackText: undefined }));
return [{ json: summary }];

const j = items[0].json;
const url = $env.SLACK_WEBHOOK_URL;
if (!url) { console.log('[pipeline-truth-sync] SLACK_WEBHOOK_URL unset; summary:\n' + j.slackText); return [{ json: { ...j, slack: 'unconfigured' } }]; }
let a = 0; const max = 4; let st = 'error';
while (a < max) {
  try { await this.helpers.httpRequest({ method: 'POST', url, body: { text: j.slackText }, json: true }); st = 'sent'; break; }
  catch (e) { if (a === max - 1) { st = 'error'; } else { await new Promise(x => setTimeout(x, Math.min(15000, 500 * 2 ** a))); } a++; }
}
return [{ json: { ...j, slack: st } }];
